#include <stdio.h>

int main(void){

    int p, q, divisor;

    printf("Please enter two numbers to find the GCD: ");
    scanf("%d%d", &p, &q);

    /* Please add your code here. Be sure to declare any additional
       variables you need. */

    printf("The greatest common divisor of %d and %d is %d.", p, q, divisor);
    return 0;
}
